('B1', 3001, $$Say x Tell$$, $$say something / tell someone$$, $$🗣️$$,
$$Use TELL quando há uma pessoa recebendo a informação (tell someone). Use SAY quando não menciona a pessoa (say something).$$,
$$Regra prática: 'tell me', 'say to me'. Nunca 'say me'.$$,
$j$[{"en": "She told me the truth.", "pt": "Ela me contou a verdade."}, {"en": "He said he was tired.", "pt": "Ele disse que estava cansado."}, {"en": "Tell me your name.", "pt": "Me diga seu nome."}]$j$::jsonb,
$j$[{"q": "Complete: She ___ me a secret.", "ctx": "", "opts": ["told", "said", "spoke", "talked"], "ans": 0, "exp": "TELL + pessoa (told me)."}, {"q": "Complete: He ___ that he was busy.", "ctx": "", "opts": ["said", "told", "told to", "say"], "ans": 0, "exp": "SAY sem pessoa (said that)."}, {"q": "Qual está errado?", "ctx": "", "opts": ["Say me the answer", "Tell me the answer", "Say hello", "Tell a story"], "ans": 0, "exp": "'Say me' não existe."}, {"q": "'Tell a lie' significa:", "ctx": "", "opts": ["contar uma mentira", "dizer a verdade", "fazer piada", "perguntar"], "ans": 0, "exp": "tell a lie = mentir."}, {"q": "Complete: Can you ___ me the time?", "ctx": "", "opts": ["tell", "say", "speak", "talk"], "ans": 0, "exp": "tell me the time."}, {"q": "Escolha o certo:", "ctx": "", "opts": ["He told us a joke.", "He said us a joke.", "He tell us a joke.", "He say a joke us."], "ans": 0, "exp": "tell + us (pessoa)."}]$j$::jsonb),

('B1', 3002, $$Lend x Borrow$$, $$emprestar x pegar emprestado$$, $$🔁$$,
$$LEND = emprestar (dar para alguém). BORROW = pegar emprestado (receber de alguém). O sentido é oposto!$$,
$$Lend TO / Borrow FROM. 'Lend me' = me empreste; 'borrow from you' = pegar de você.$$,
$j$[{"en": "Can you lend me your pen?", "pt": "Pode me emprestar sua caneta?"}, {"en": "I borrowed this book from the library.", "pt": "Peguei este livro emprestado da biblioteca."}, {"en": "He lent me some money.", "pt": "Ele me emprestou dinheiro."}]$j$::jsonb,
$j$[{"q": "'Me empreste' =", "ctx": "", "opts": ["Lend me", "Borrow me", "Lend from me", "Borrow to me"], "ans": 0, "exp": "lend me."}, {"q": "'Peguei emprestado do João' =", "ctx": "", "opts": ["I borrowed from João", "I lent from João", "I borrowed to João", "I lend João"], "ans": 0, "exp": "borrow from."}, {"q": "LEND significa:", "ctx": "", "opts": ["emprestar (dar)", "pegar emprestado", "comprar", "vender"], "ans": 0, "exp": "lend = dar emprestado."}, {"q": "Complete: Can I ___ your car?", "ctx": "", "opts": ["borrow", "lend", "lend to", "borrow to"], "ans": 0, "exp": "borrow (pegar emprestado)."}, {"q": "Complete: I'll ___ you my umbrella.", "ctx": "", "opts": ["lend", "borrow", "borrow from", "lend from"], "ans": 0, "exp": "lend you (te emprestar)."}, {"q": "Passado de 'lend':", "ctx": "", "opts": ["lent", "lended", "borrowed", "lend"], "ans": 0, "exp": "lend -> lent."}]$j$::jsonb),

('B1', 3003, $$Bring x Take$$, $$trazer x levar$$, $$👐$$,
$$BRING = trazer (para perto de quem fala). TAKE = levar (para longe de quem fala). Depende do ponto de referência.$$,
