$j$[{"en": "Bring me a glass of water, please.", "pt": "Me traga um copo de água."}, {"en": "Take your umbrella when you go out.", "pt": "Leve seu guarda-chuva ao sair."}, {"en": "I'll bring dessert to the party.", "pt": "Vou levar a sobremesa para a festa."}]$j$::jsonb,
$j$[{"q": "'Me traga o livro' =", "ctx": "", "opts": ["Bring me the book", "Take me the book", "Bring the book there", "Take here the book"], "ans": 0, "exp": "bring (para perto)."}, {"q": "'Leve isto para ela' =", "ctx": "", "opts": ["Take this to her", "Bring this to her", "Take here this", "Bring there this"], "ans": 0, "exp": "take (para longe)."}, {"q": "BRING indica movimento:", "ctx": "", "opts": ["em direção a quem fala", "para longe", "para cima", "nenhum"], "ans": 0, "exp": "trazer = para perto."}, {"q": "Complete: Don't forget to ___ your ID to the exam.", "ctx": "", "opts": ["take", "bring", "take to", "bring here"], "ans": 0, "exp": "take (levar para lá)."}, {"q": "Passado de 'bring':", "ctx": "", "opts": ["brought", "bringed", "brang", "brought to"], "ans": 0, "exp": "bring -> brought."}, {"q": "Passado de 'take':", "ctx": "", "opts": ["took", "taked", "taken", "take"], "ans": 0, "exp": "take -> took."}]$j$::jsonb),

