$j$[{"q": "'Me lembre de pagar' =", "ctx": "", "opts": ["Remind me to pay", "Remember me to pay", "Remind to pay me", "Remember to pay me"], "ans": 0, "exp": "remind me to."}, {"q": "'Eu lembro do nome dele' =", "ctx": "", "opts": ["I remember his name", "I remind his name", "I remember him name", "I remind of his name"], "ans": 0, "exp": "remember (eu lembro)."}, {"q": "REMIND precisa de:", "ctx": "", "opts": ["alguém para lembrar", "nada", "um objeto só", "um verbo no passado"], "ans": 0, "exp": "remind + someone."}, {"q": "Complete: You ___ me of my brother.", "ctx": "", "opts": ["remind", "remember", "reminds to", "remember to"], "ans": 0, "exp": "remind me of (me faz lembrar)."}, {"q": "Complete: Did you ___ to lock the door?", "ctx": "", "opts": ["remember", "remind", "reminded", "remember of"], "ans": 0, "exp": "remember to (lembrar de fazer)."}, {"q": "'Remind' significa:", "ctx": "", "opts": ["fazer alguém lembrar", "esquecer", "memorizar sozinho", "anotar"], "ans": 0, "exp": "lembrar alguém."}]$j$::jsonb),

('B2', 3005, $$Raise x Rise$$, $$levantar algo x subir$$, $$📈$$,
