('B2', 3006, $$Lie x Lay$$, $$deitar x colocar (deitar algo)$$, $$🛏️$$,
$$LIE (lie-lay-lain) = deitar-se (sem objeto). LAY (lay-laid-laid) = colocar/deitar ALGO (com objeto). Confusão clássica até para nativos.$$,
$$I lie down (eu me deito). I lay the book on the table (coloco o livro). Cuidado: passado de 'lie' é 'lay'.$$,
$j$[{"en": "I lie down when I am tired.", "pt": "Eu me deito quando estou cansado."}, {"en": "Lay the baby on the bed.", "pt": "Deite o bebê na cama."}, {"en": "She laid the keys on the table.", "pt": "Ela colocou as chaves na mesa."}]$j$::jsonb,
$j$[{"q": "'Eu me deito' (agora) =", "ctx": "", "opts": ["I lie down", "I lay down", "I laid down", "I lain down"], "ans": 0, "exp": "lie down (deitar-se)."}, {"q": "'Coloque o livro aqui' =", "ctx": "", "opts": ["Lay the book here", "Lie the book here", "Lay down the book yourself", "Lie down the book"], "ans": 0, "exp": "lay + objeto."}, {"q": "LAY precisa de objeto?", "ctx": "", "opts": ["sim", "não", "nunca", "raramente"], "ans": 0, "exp": "lay é transitivo."}, {"q": "Passado de 'lay' (colocar):", "ctx": "", "opts": ["laid", "lay", "lain", "layed"], "ans": 0, "exp": "lay -> laid."}, {"q": "Passado de 'lie' (deitar):", "ctx": "", "opts": ["lay", "laid", "lied", "lain"], "ans": 0, "exp": "lie -> lay (confuso!)."}, {"q": "'Lie' (mentir) é diferente? Passado:", "ctx": "", "opts": ["lied", "lay", "laid", "lain"], "ans": 0, "exp": "lie(mentir) -> lied."}]$j$::jsonb),

