('C2', 3020, $$Understatement e ironia britânica$$, $$'not bad' = ótimo$$, $$🇬🇧$$,
$$No inglês britânico, understatement suaviza de propósito: 'not bad' pode significar excelente; 'a bit of a problem' pode ser um desastre. Entender o tom evita mal-entendidos.$$,
$$Muitas vezes o significado real é mais forte do que as palavras sugerem.$$,
$j$[{"en": "'It's not bad at all.' (means: it's great)", "pt": "'Nada mal.' (significa: ótimo)"}, {"en": "'We have a slight problem.' (means: big trouble)", "pt": "'Temos um probleminha.' (significa: encrenca séria)"}, {"en": "'I'm not entirely happy.' (means: very upset)", "pt": "'Não estou totalmente feliz.' (significa: muito chateado)"}]$j$::jsonb,
$j$[{"q": "'Not bad' (understatement) costuma significar:", "ctx": "", "opts": ["muito bom", "péssimo", "normal", "estranho"], "ans": 0, "exp": "understatement positivo."}, {"q": "'A slight problem' pode na verdade ser:", "ctx": "", "opts": ["um problemão", "nada", "uma dúvida", "uma piada"], "ans": 0, "exp": "suavização."}, {"q": "Understatement serve para:", "ctx": "", "opts": ["suavizar / soar educado", "exagerar", "ofender", "confundir de propósito"], "ans": 0, "exp": "suavizar."}, {"q": "'I'm not entirely convinced' =", "ctx": "", "opts": ["discordo bastante", "concordo 100%", "não entendi", "estou animado"], "ans": 0, "exp": "discordância educada."}, {"q": "Isso é mais típico do inglês:", "ctx": "", "opts": ["britânico", "americano informal", "técnico", "antigo"], "ans": 0, "exp": "britânico."}, {"q": "Ler understatement exige atenção ao:", "ctx": "", "opts": ["tom e contexto", "dicionário só", "sotaque", "tempo verbal"], "ans": 0, "exp": "tom/contexto."}]$j$::jsonb);
